INSERT INTO `bot_faq` VALUES (1,'tiempo de entrega, cuánto tarda, cuanto tarda, tiempo estimado, días de entrega, plazo de entrega, tiempo del proceso, duración del servicio, cuánto tiempo es, cuanto tiempo es, días hábiles, tiempo aproximado','⏱️ El tiempo varía según el tipo de equipo. Calibraciones estándar (temperatura, presión) tardan 10 días hábiles En-Laboratorio. Para En sitio coordinamos la fecha contigo. Solicita tu cotización escribiendo *2*.',1,11,'2026-03-30 15:04:37'),(2,'costo, costos, precio, precios, cuánto cuesta, cuanto cuesta, cuánto vale, cuanto vale, tarifa, tarifas, presupuesto, presupuestos, valor, inversión, importe, monto, dinero, pago, pagos,','? Los precios varían según tipo de equipo, magnitud y modalidad (en-Laboratorio o en sitio). Te preparamos una cotización personalizada sin costo. Escribe *2* para solicitarla.',1,9,'2026-03-30 15:04:37'),(3,'ISO, iso, acreditación, acreditaciones, certificado iso, certificación iso, iso 17025, iso/iec 17025, norma iso, cumplen iso, están acreditados, tienen certificación, laboratorio acreditado, ema, pjla, acreditación ema, acreditación pjla','✅ Sí. SICAMET está acreditado bajo *ISO/IEC 17025:2017* por la EMA y PJLA con reconocimiento internacional. Contamos con *12 acreditaciones vigentes*  Presión · Temperatura · Fuerza · Masa · Eléctrica · Dimensional · Flujo · Humedad · Óptica · Volumen · Analizadores específicos (dinamómetros vehiculares) · Mediciones Especiales.',1,10,'2026-03-30 15:04:37'),(4,'en sitio, in situ, in-situ, a domicilio, en campo, en planta, en mis instalaciones, en mi empresa, en mi negocio, visita técnica, servicio externo, fuera del laboratorio, en ubicación del comprador, van a mi ubicación, pueden venir','✅ Sí, ofrecemos servicio *En sitio* — nuestros técnicos van a tus instalaciones. Ideal para equipos que no pueden tener tiempo de inactividad. Escribe *2* para cotizar.',1,25,'2026-03-30 15:04:37'),(5,'vaisala, partner vaisala, distribuidor vaisala, certificado vaisala, alianza vaisala, socios vaisala, representante vaisala, soporte vaisala, servicio vaisala, mantenimiento vaisala, sensores vaisala','✅ SICAMET es el *único partner de calibración y mantenimiento Vaisala en México*, certificado oficialmente. Gestionamos garantías, sensores y calibraciones.',1,5,'2026-03-30 15:04:37'),(6,'qué magnitudes, tipos de magnitudes, magnitudes disponibles, áreas de medición, tipos de medición, categorías de calibración, disciplinas de calibración, campos de calibración, especialidades de calibración, tipos de pruebas','? Calibramos: Presión · Temperatura · Fuerza · Masa · Eléctrica · Dimensional · Flujo · Humedad · Óptica · Volumen · Analizadores específicos (dinamómetros vehiculares) · Mediciones Especiales.',1,6,'2026-03-30 15:04:37'),(7,'ubicación, ubicaciones, dónde están, donde estan, dirección, direcciones, sucursales, sedes, oficinas, en qué ciudad están, en que ciudad estan, dónde se ubican, donde se ubican, domicilio','? Contamos con sede en:\n• *Toluca* Juan Aldama Sur 1135 Col. Universidad C.P. 50130 Toluca, Edo. de México\n\n⏰ Lun–Vie 8:00–18:00 | ? 722 264 0245',1,12,'2026-03-30 15:04:37'),(8,'hora, horarios, reloj, hora abren, hora cierran, a qué hora abren, a que hora abren, a qué hora cierran, a que hora cierran, hora de atención, horas de atención, ','Horario de Lunes a Viernes de 8:00 am a 18:00 pm ',1,22,'2026-03-30 21:24:47');
