INSERT INTO `bot_mensajes` VALUES ('bienvenida_conocido','¡Hola de nuevo, *{nombre}*! ? ¿En qué te podemos ayudar hoy?','Cliente ya registrado',1,'2026-03-30 15:04:37'),('bienvenida_nuevo','¡Hola! ? Bienvenido a *SICAMET*, laboratorio de calibración con 21 años de experiencia.\n\nAntes de continuar, ¿me podrías decir tu *nombre y empresa*?\n\n_Ejemplo: Juan García, Alimentos del Norte_','Primera vez que escribe el cliente',1,'2026-03-30 15:04:37'),('cotizacion_recibida','✅ *¡Solicitud de cotización recibida!*\n\n? Resumen:\n• Equipo: *{equipo}*\n• Cantidad: *{cantidad}*\n• Servicio: *{servicio}*\n• Empresa: *{empresa}*\n\n? Un asesor de SICAMET te contactará pronto con tu cotización.\n\n? *722 270 1584* | ? *sclientes@sicamet.net*\n\n_Escribe *0* para volver al menú_','Confirmación de cotización completada',1,'2026-03-30 15:04:37'),('escalado_humano','?‍? *Transfiriendo con un asesor de SICAMET...*\n\nUn especialista revisará tu consulta y te contactará en breve.\n\n? *722 270 1584 | 722 212 0722*\n? *sclientes@sicamet.net*\n⏰ Lun–Vie 8:00–18:00\n\n_Escribe *0* para volver al menú_','Respuesta al escalar a humano',1,'2026-03-30 15:04:37'),('estatus_no_encontrado','❌ No encontramos la orden *{orden}* en nuestro sistema.\n\nVerifica el número o escribe *6* para que un asesor te ayude.\n\n? 722 270 1584','Cuando no se encuentra la orden',1,'2026-03-30 15:04:37'),('fuera_horario','? Gracias por contactar a *SICAMET*.\n\nNuestro horario de atención es *Lunes a Viernes 8:00–18:00 hrs*.\n\nTu mensaje quedó registrado y te responderemos al inicio del siguiente día hábil.\n\n? Urgencias: *722 270 1584*\n? sclientes@sicamet.net','Mensaje fuera de horario laboral',1,'2026-03-30 15:04:37'),('menu_principal','¡Hola! ? Soy el asistente virtual de *SICAMET*.\n\n¿En qué te podemos ayudar hoy?\n\n*1️⃣* ? Solicitar cotización\n*2️⃣* ? Consultar estatus de equipo\n*3️⃣* ? Mis equipos y recordatorios\n*4️⃣* ? Servicios y acreditaciones\n*5️⃣* ? Contacto\n*6️⃣* ?‍? Hablar con un asesor\n\n_Escribe el número de tu opción_','Menú principal del bot',1,'2026-03-30 15:04:37');
