INSERT INTO `bot_nodos` VALUES (1,'Flujo Cotización','? *Menú de Cotizaciones*\n\n¿Qué tipo de cotización deseas solicitar?\n\n*1️⃣* Calibración de Instrumentos\n*2️⃣* Calificación de Equipos/Áreas\n*3️⃣* Verificentro (Masa/Volumen)\n*4️⃣* Ventas de Instrumentos\n\n_Escribe el número de tu opción._','opciones','cotizacion',NULL,NULL,2),(2,'Consulta Estatus de Equipo','? Escribe el *número de orden de servicio*:\n\n_Ejemplo: O26-04XX_','input','consultar_estatus',NULL,NULL,7),(3,'Registro Equipos (Próxima Calibración)','? *Registro de Instrumentos*\n\nTe avisaré antes de que venza tu certificado. ?\n\n¿Cuál es el nombre de tu empresa?','input','registrar_equipo',NULL,NULL,9),(4,'Servicios','? *Servicios SICAMET*\n\n✅ Calibración In-Lab / In-situ\n✅ Alta Tecnología y Acreditaciones:  Presión · Temperatura · Fuerza · Masa · Eléctrica · Dimensional · Flujo · Humedad · Óptica · Volumen · Analizadores específicos (dinamómetros vehiculares) · Mediciones Especiales.','mensaje','servicios',NULL,NULL,6),(5,'Contacto','? *Contacto SICAMET*\n\n⌚ Lunes a Viernes de 8:00am a 18:00p\n? sclientes@sicamet.net\n? C. Juan Aldama 1135, Universidad, 50130 Toluca de Lerdo, Méx.\n? Sitio Web: https://www.sicamet.mx/\n\n_Escribe ASESOR para conectar con nuestro equipo_.','mensaje','contacto','https://www.sicamet.mx/','document',10),(6,'Hablar con Asesor','?‍? Por favor, escribe en un solo mensaje el motivo por el cual deseas contactar a un asesor:','mensaje','escalar','','document',11),(7,'Soy Cliente','? *Identificación de Cliente*\n\nPor favor, escribe el nombre de tu EMPRESA o RAZÓN SOCIAL en MAYÚSCULAS para darte una bienvenida personalizada.\n\nEjemplo: *MEXICANA PRO*','mensaje','identificar_cliente',NULL,NULL,1),(8,'Buzón de Sugerencias','? *Buzón de Quejas y Sugerencias*\n\nNos interesa mucho tu opinión para seguir mejorando.\n\nPor favor, *escribe tu sugerencia o queja* en un solo mensaje:\n\n_Escribe *0* para cancelar y volver._','input','feedback',NULL,NULL,12),(10,'Consultar mi Certificado','? Escribe el *Número de Orden* o el *Número de Informe* que deseas consultar.','input','consultar_certificado',NULL,NULL,8),(11,'Cotización de Calificación','?️ *Cotización de Calificación*\n\n¿Qué área de calificación requieres?\n\n*1️⃣* Equipos (Estufa, Baños, Autoclaves, etc.)\n*2️⃣* Mapeo Térmico (Almacén, Recintos, etc.)\n\n_Escribe 1 o 2_','input','calificacion',NULL,NULL,3),(12,'Cotización de Verificentro','✅ *Cotización de Verificentro*\n\n¿Cuántas *líneas* tiene el verificentro?\n\n_Escribe el número de líneas. Ej: 4_','input','verificentro',NULL,NULL,4),(13,'Ventas de Instrumentos','? *Ventas de Instrumentos*\n\nDescribe el instrumento que requieres:\n\n_Ej: Termohigrómetro certificado por ema iso 17025, puntos 20/50/75% HR_','input','ventas',NULL,NULL,5);
