INSERT INTO `nodos` VALUES (1,'BIENVENIDA','¡Hola! ? Bienvenido al asistente inteligente de *SICAMET*.\n\n¿En qué podemos ayudarte hoy?\n\n1. Ver Servicios ?\n2. Ubicación y Horarios ?\n3. Ver las 12 Acreditaciones (ema) ?\n4. Rastrear mi Instrumento (SLA 10 días) ?\n5. Hablar con un asesor ?','MENU'),(2,'SERVICIOS','En *SICAMET* ofrecemos soluciones integrales:\n\n✅ *Calibración:* In-Lab e In-Situ (ISO/IEC 17025).\n✅ *Calificación:* Áreas y equipos para sector farma/médico.\n✅ *Consultoría:* Metrología y gestión de calidad.\n\n_Más detalles en: sicamet.mx/servicios_','INFO'),(3,'UBICACION','? *Dirección:* C. Juan Aldama 1135, Universidad, 50130 Toluca de Lerdo, Méx.\n\n⏰ *Horario:* Lunes a Viernes de 8:00 AM a 6:00 PM.\n? *Web:* sicamet.mx','INFO'),(4,'ACREDITACIONES','Laboratorio acreditado por la *ema* en:\n\n1. Analizadores específicos (AE-18)\n2. Dimensional (D-145)\n3. Eléctrica (E-111)\n4. Fuerza (F-44)\n5. Flujo (FL-20)\n6. Humedad (H-11)\n7. Masa (M-77)\n8. Mediciones Especiales (ME-01)\n9. Óptica (OP-21)\n10. Presión (P-51)\n11. Temperatura (T-56)\n12. Volumen (V-40)\n\n_Todos nuestros servicios avalan la Norma ISO/IEC 17025:2017._','INFO'),(5,'RASTREO_INICIO','? *Seguimiento de Instrumentos*\n\nPor favor, ingresa tu *Número de Referencia o Cotización* para verificar en qué etapa del flujo de 10 días se encuentra tu equipo:','RASTREO');
/*!40000 ALTER TABLE `nodos` ENABLE KEYS */;
UNLOCK TABLES;

